import { Component, inject, signal } from "@angular/core";
import { FormsModule } from "@angular/forms";
import { LoginService } from "./login.service";

@Component({
  selector: "app-root",
  templateUrl: "./app.html",
  styleUrl: "./app.css",
  imports: [FormsModule],
})
export class App {
  private loginService = inject(LoginService);

  email = signal("");
  password = signal("");
  isLoggedIn = signal(false);

  login() {
    const emailValue = this.email();
    const passwordValue = this.password();

    this.loginService.login(emailValue, passwordValue).subscribe(() => {
      this.isLoggedIn.set(true);
    });
  }
}

export interface LoginRequest {
  email: string;
  password: string;
}

export interface LoginResponse {
  accessToken: string;
}

import { Injectable, inject } from "@angular/core";
import { HttpClient } from "@angular/common/http";
import { Observable } from "rxjs";
import { LoginRequest, LoginResponse } from "./login.model";

@Injectable({
  providedIn: "root",
})
export class LoginService {
  private http = inject(HttpClient);
  private apiUrl = "https://us-central1-lowgular-platform-c0e93.cloudfunctions.net/api/mock/login";

  login(email: string, password: string): Observable<LoginResponse> {
    const request: LoginRequest = { email, password };
    return this.http.post<LoginResponse>(this.apiUrl, request);
  }
}

